const reply =$input.first().json.output
const chatId =$('Telegram Trigger').first().json.message.chat.id

const MAX_LENGTH = 3500; // safe buffer under 4096

// If short enough, send as-is
if (reply.length <= MAX_LENGTH) {
  return [{ json: { chatId, reply } }];
}

// Split into chunks
const chunks = [];
let text = reply;

while (text.length > 0) {
  // Try to split at newline for cleaner breaks
  let splitAt = MAX_LENGTH;
  const lastNewline = text.lastIndexOf('\n', MAX_LENGTH);

  if (lastNewline > MAX_LENGTH * 0.5) {
    splitAt = lastNewline; // split at natural line break
  }

  chunks.push(text.slice(0, splitAt).trim());
  text = text.slice(splitAt).trim();
}

// Return each chunk as separate item
return chunks.map(chunk => ({
  json: { chatId, reply: chunk }
}));

// ─── n8n Code Node (Google Sheets-ready) ─────────────────────
const text = $input.first().json.output;

const lines = text.split('\n').filter(l => l.trim().startsWith('|'));

const rows = lines
  .map(l => l.split('|').map(c => c.trim()).filter(c => c !== ''))
  .filter(r => r.length >= 8 
    && !r[0].startsWith(':') 
    && !r[0].startsWith('Tanggal'));

// Return one item per row — each becomes a spreadsheet row
return rows.map(r => ({
  json: {
    Tanggal:      r[0].replace(/\*/g, ''),
    WL:           r[1],
    Keys:         r[2],
    Drum:         r[3],
    Guitar:       r[4],
    Bass:         r[5],
    Singers_Sesi1: r[6],
    Singers_Sesi2: r[7],
  }
}));

const reply = $input.first().json.output;
const chatId = $('Telegram Trigger').first().json.message.chat.id;

// Convert markdown to Telegram-compatible format
function convertToTelegram(text) {
  return text
    // Bold: **text** → *text* (Telegram markdown)
    .replace(/\*\*(.*?)\*\*/g, '*$1*')

    // Bullet points: "*   text" or "-   text" → "• text"
    .replace(/^\*\s+/gm, '• ')
    .replace(/^-\s+/gm, '• ')

    // Remove leftover single * that are not bold
    .replace(/(?<!\*)\*(?!\*)/g, '')

    // Clean up excessive newlines
    .replace(/\n{3,}/g, '\n\n')

    .trim();
}

const converted = convertToTelegram(reply);
const MAX_LENGTH = 3500;

if (converted.length <= MAX_LENGTH) {
  return [{ json: { chatId, reply: converted } }];
}

// Split into chunks
const chunks = [];
let text = converted;

while (text.length > 0) {
  let splitAt = MAX_LENGTH;
  const lastNewline = text.lastIndexOf('\n', MAX_LENGTH);
  if (lastNewline > MAX_LENGTH * 0.5) {
    splitAt = lastNewline;
  }
  chunks.push(text.slice(0, splitAt).trim());
  text = text.slice(splitAt).trim();
}

return chunks.map(chunk => ({ json: { chatId, reply: chunk } }));
